# shellcheck shell=bash
write_bootstrap_state() {
    local temp_state

    echo ""
    echo "--- Writing state file: $STATE_FILE ---"

    mkdir -p "$(dirname "$STATE_FILE")"
    temp_state=$(mktemp)
    trap 'rm -f "$temp_state"' RETURN

    cat > "$temp_state" <<EOF
# Auto-generated by bootstrap-zitadel.sh — do not edit manually
# Re-run bootstrap to regenerate
ZITADEL_CLIENT_PROJECT_ID=${PROJECT_ID}
ZITADEL_PROJECT_NAME=${PROJECT_NAME}
ZITADEL_DEFAULT_ORG_ID=${DEFAULT_ORGANIZATION_ID}
FM_CLIENT_ORG_ID=${ORGANIZATION_ID}
FM_PLATFORM_ORG_ID=${PLATFORM_ORGANIZATION_ID}
ZITADEL_CLIENT_BACKEND_APP_ID=${BACKEND_APP_ID}
ZITADEL_CLIENT_BACKEND_CLIENT_ID=${BACKEND_CLIENT_ID}
ZITADEL_CLIENT_BACKEND_CLIENT_SECRET=${BACKEND_CLIENT_SECRET}
ZITADEL_BACKEND_AUTH_METHOD=${FM_OIDC_AUTH_METHOD}
ZITADEL_BACKEND_KEY_FILE=${OIDC_INTROSPECTION_KEY_FILE}
ZITADEL_CLIENT_FRONTEND_APP_ID=${FRONTEND_APP_ID}
ZITADEL_CLIENT_FRONTEND_CLIENT_ID=${FRONTEND_CLIENT_ID}
ZITADEL_ISSUER_URL=${ZITADEL_PUBLIC_URL}
ZITADEL_AUTH_ENDPOINT=${ZITADEL_PUBLIC_URL}/oauth/v2/authorize
ZITADEL_TOKEN_ENDPOINT=${ZITADEL_PUBLIC_URL}/oauth/v2/token
ZITADEL_USERINFO_ENDPOINT=${ZITADEL_PUBLIC_URL}/oidc/v1/userinfo
ZITADEL_END_SESSION_ENDPOINT=${ZITADEL_PUBLIC_URL}/oidc/v1/end_session
ZITADEL_SERVICE_TOKEN=${SERVICE_PAT}
ZITADEL_SERVICE_USER_ID=${SERVICE_USER_ID:-}
ZITADEL_SERVICE_AUTH_METHOD=${FM_ZITADEL_SERVICE_AUTH}
ZITADEL_SERVICE_KEY_FILE=${ZITADEL_SERVICE_KEY_FILE}
ZITADEL_LOGIN_CLIENT_TOKEN=${LOGIN_CLIENT_PAT:-}
ZITADEL_LOGIN_CLIENT_USER_ID=${LOGIN_CLIENT_USER_ID:-}
FM_PLATFORM_ADMIN_USER_ID=${PLATFORM_ADMIN_USER_ID:-}
FM_PLATFORM_ADMIN_USER=${FM_PLATFORM_ADMIN_USER}
FM_PLATFORM_ADMIN_EMAIL=${FM_PLATFORM_ADMIN_EMAIL}
FM_PLATFORM_ADMIN_ROLE=${FM_PLATFORM_ADMIN_ROLE}
FM_PLATFORM_SUPPORT_READ_ROLE=${FM_PLATFORM_SUPPORT_READ_ROLE}
FM_ZITADEL_SERVICE_INSTANCE_ROLE=${FM_ZITADEL_SERVICE_INSTANCE_ROLE}
FM_NODE_RED_SERVICE_TOKEN=${NODE_RED_SERVICE_PAT:-}
FM_NODE_RED_SERVICE_USER_ID=${NODE_RED_SERVICE_USER_ID:-}
FM_NODE_RED_ORG_ID=${ORGANIZATION_ID}
FM_NODE_RED_PERMISSIONS=${NODE_RED_PERMISSIONS:-}
FM_NODE_RED_PROXY_SECRET=${NODE_RED_PROXY_SECRET:-}
FM_NODE_RED_CREDENTIAL_SECRET=${NODE_RED_CREDENTIAL_SECRET:-}
FM_GRAFANA_SERVICE_TOKEN=${GRAFANA_SERVICE_PAT:-}
FM_GRAFANA_SERVICE_USER_ID=${GRAFANA_SERVICE_USER_ID:-}
FM_GRAFANA_ORG_ID=${ORGANIZATION_ID}
FM_GRAFANA_PERMISSIONS=${GRAFANA_PERMISSIONS:-}
FM_GRAFANA_PROXY_SECRET=${GRAFANA_PROXY_SECRET:-}
EOF

    chmod 0600 "$temp_state"
    mv "$temp_state" "$STATE_FILE"
    trap - RETURN

    echo "  State file written"
}

print_bootstrap_summary() {
    echo ""
    echo "=== Bootstrap complete ==="
    echo "  Project:          $PROJECT_ID"
    echo "  Root org:         $DEFAULT_ORGANIZATION_ID"
    echo "  Tenant org:       $ORGANIZATION_ID"
    echo "  Platform org:     $PLATFORM_ORGANIZATION_ID"
    echo "  Backend client:   $BACKEND_CLIENT_ID"
    echo "  Frontend client:  $FRONTEND_CLIENT_ID"
    echo "  Service user:     ${SERVICE_USER_ID:-none}"
    echo "  Service PAT:      ${SERVICE_PAT:+configured}"
    echo "  Login client:     ${LOGIN_CLIENT_USER_ID:-none}"
    echo "  Login PAT:        ${LOGIN_CLIENT_PAT:+configured}"
    echo "  Platform admin:   ${FM_PLATFORM_ADMIN_USER:-none}"
    echo "  Platform pass:    ${FM_PLATFORM_ADMIN_PASSWORD:+configured}"
    echo "  Node-RED user:    ${NODE_RED_SERVICE_USER_ID:-none}"
    echo "  Node-RED PAT:     ${NODE_RED_SERVICE_PAT:+configured}"
    echo "  Grafana user:     ${GRAFANA_SERVICE_USER_ID:-none}"
    echo "  Grafana PAT:      ${GRAFANA_SERVICE_PAT:+configured}"
}
